I think I found a cute new writing haunt and I'm so excited. Sitting in quiet coffee shops is basically my favourite thing to do, especially when they're as cute and the food as delicious as this one "},{"type":"emoji","name":"blob_excited"}]}]}],"type":"message","ts":"1775240501.401659","client_msg_id":"8250f85c-f03e-4f2f-b250-2a77937dc330","thread_ts":"1775240501.401659","reply_count":7,"reply_users_count":6,"latest_reply":"1775474093.037169","reply_users":["U03TKASL8J2","U049SSEC90T","U086J1D81NJ","U01NYR15VE0","U0401BVRA04","U02EH242ARJ"],"is_locked":false,"subscribed":false,"reactions":[{"name":"blob_aww","users":["U03TKASL8J2","U049SSEC90T","U03MTKE9Q80","U044SBPRH6C","U04SWK60P1T","U03JSMAGHQC","U05QWLQQ3L3","U02BFB6T9V5","U02EH242ARJ"],"count":9},{"name":"heart_eyes","users":["U03TKASL8J2","U049SSEC90T","U03MTKE9Q80","U044SBPRH6C","U04SWK60P1T","U03JSMAGHQC","U05QWLQQ3L3","U02EH242ARJ"],"count":8},{"name":"coffee","users":["U03TKASL8J2","U044SBPRH6C","U04SWK60P1T","U03JSMAGHQC","U05QWLQQ3L3","U02EH242ARJ"],"count":6},{"name":"rainbow_sparkles","users":["U02EH242ARJ"],"count":1},{"name":"gem-heart","users":["U02EH242ARJ"],"count":1}]}

